import sys
input = sys.stdin.readline

def main():
    q = int(input())
    queries = []
    for _ in range(q):
        line = input().split()
        if line[0] == '1':
            queries.append((1, int(line[1])))
        else:
            queries.append((2, int(line[1]), int(line[2])))

    parent = list(range(500002))

    def find(x):
        while parent[x] != x:
            parent[x] = parent[parent[x]]
            x = parent[x]
        return x

    result = []
    for i in range(len(queries) - 1, -1, -1):
        query = queries[i]
        if query[0] == 1:
            result.append(find(query[1]))
        else:
            x, y = query[1], query[2]
            fx = find(x)
            fy = find(y)
            if fx != fy:
                parent[fx] = fy

    result.reverse()
    print(*result)

main()

